query:
SELECT id, sku, description, tenantId FROM products WHERE id = 59188 LIMIT 1;

SELECT i.id, i.productId, i.tenantId, i.quantity, i.reservedQuantity, i.locationZone, wl.code as locationCode
FROM inventory i
LEFT JOIN warehouseLocations wl ON i.locationId = wl.id
WHERE wl.code = 'M03-01-39'
LIMIT 5;

